#include<bits/stdc++.h>
using namespace std;
unsigned int n,m,a[1000010],b[1000010],c[1000010];
vector<pair<unsigned int,unsigned int>> v[1000010];
unsigned int ans[5000010],x[1000010],y[1000010],z[1000010],cnt;
unsigned int calc(unsigned int v)
{
	return x[v]+y[v]*(cnt-z[v]);
}
int main()
{
	scanf("%u%u",&n,&m);
	for(unsigned int i=1;i<=n;i++)
	{
		scanf("%u",&a[i]);
	}
	for(unsigned int i=1;i<=n;i++)
	{
		scanf("%u",&b[i]);
	}
	for(unsigned int i=1;i<=n;i++)
	{
		scanf("%u",&c[i]);
	}
	for(unsigned int i=1;i<=m;i++)
	{
		unsigned int l,r;
		scanf("%u%u",&l,&r);
		v[r].push_back({l,i});
	}
	for(unsigned int i=1;i<=n;i++)
	{
		unsigned int p=i-1;
		while(p)
		{
			unsigned int u=(a[p]&a[p+1]),v=(b[p]|b[p+1]),w=gcd(c[p],c[p+1]);
			if(u==a[p]&&v==b[p]&&w==c[p])
			{
				break;
			}
			a[p]=u;
			b[p]=v;
			c[p]=w;
			p--;
		}
		x[i]=calc(i-1);
		for(unsigned int j=p+1;j<=i;j++)
		{
			x[j]=calc(j);
			y[j]=y[j-1]+a[j]*b[j]*c[j];
			z[j]=cnt;
		}
		cnt++;
		for(auto j:v[i])
		{
			unsigned int l=j.first,id=j.second;
			ans[id]=calc(i)-calc(l-1);
		}
	}
	for(unsigned int i=1;i<=m;i++)
	{
		printf("%u\n",ans[i]);
	}
	return 0;
}
